module SR_latch (input Anti_S, input R, output reg Q, output Qn);  
    always @(Anti_S, R) begin  
        if (Anti_S && !R)  
            Q <= 1;  
        else if (!Anti_S && R)  
            Q <= 0;  
        // If both Anti_S and R are low, retain previous state  
    end  
    assign Qn = ~Q;  
endmodule
